def gen(rng, size):
    import string
    n = max(1, size)
    L = rng.randint(1, 10)
    def rand_word():
        return ''.join(rng.choice(string.ascii_lowercase) for _ in range(L))
    dictionary = [rand_word() for _ in range(max(1, n // 2))]
    queries = []
    for _ in range(n):
        if rng.random() < 0.5 and dictionary:
            base = list(rng.choice(dictionary))
            k = rng.randint(0, 3)
            idxs = rng.sample(range(L), min(k, L))
            for i in idxs:
                base[i] = rng.choice(string.ascii_lowercase)
            queries.append(''.join(base))
        else:
            queries.append(rand_word())
    return [queries, dictionary]

