class Solution:
    def twoEditWords(self, queries, dictionary):
        res = []
        for q in queries:
            ok = False
            for d in dictionary:
                diff = sum(1 for a, b in zip(q, d) if a != b)
                if diff <= 2:
                    ok = True
                    break
            if ok:
                res.append(q)
        return res

