class Solution:
    def twoEditWords(self, queries, dictionary):
        def within(q, d):
            cnt = 0
            for i in range(len(q)):
                if q[i] != d[i]:
                    cnt += 1
                    if cnt > 2:
                        return False
            return True
        return [q for q in queries if any(within(q, d) for d in dictionary)]

