var twoEditWords = function(queries, dictionary) {
    const within = (q, d) => {
        let cnt = 0;
        for (let i = 0; i < q.length; i++) {
            if (q[i] !== d[i]) {
                cnt++;
                if (cnt > 2) return false;
            }
        }
        return true;
    };
    return queries.filter(q => dictionary.some(d => within(q, d)));
};
